diff --git a/llvm/lib/Transforms/InstCombine/InstCombineVectorOps.cpp b/llvm/lib/Transforms/InstCombine/InstCombineVectorOps.cpp
index 454fe5a91d37..ee59215db2ea 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineVectorOps.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineVectorOps.cpp
@@ -2905,8 +2905,14 @@ Instruction *InstCombinerImpl::visitShuffleVectorInst(ShuffleVectorInst &SVI) {
       // We cannot do this fold for elementwise select since ShuffleVector is
       // not elementwise.
       if (SI->getCondition()->getType()->isIntegerTy()) {
-        if (Instruction *I = FoldOpIntoSelect(SVI, SI))
-          return I;
+        // Check that all mask elements select from LHS (the select) and not from RHS.
+        // If any mask element selects from RHS, folding is unsafe because when the
+        // select condition is poison, those lanes would become poison in the
+        // transformed code but not in the original.
+        if (all_of(Mask, [LHSWidth](int M) { return M == -1 || (unsigned)M < LHSWidth; })) {
+          if (Instruction *I = FoldOpIntoSelect(SVI, SI))
+            return I;
+        }
       }
     }
     if (auto *PN = dyn_cast<PHINode>(LHS)) {
@@ -2919,7 +2925,6 @@ Instruction *InstCombinerImpl::visitShuffleVectorInst(ShuffleVectorInst &SVI) {
     Value *V = evaluateInDifferentElementOrder(LHS, Mask, Builder);
     return replaceInstUsesWith(SVI, V);
   }
-
   // SROA generates shuffle+bitcast when the extracted sub-vector is bitcast to
   // a non-vector type. We can instead bitcast the original vector followed by
   // an extract of the desired element:

